```class Solution:
    def sequentialDigits(self, low: int, high: int) -> List[int]:
        res = []
        for length in range(len(str(low)), len(str(high)) + 1):
            for start in range(1, 10 - length):
                num = 0
                for i in range(length):
                    num = num * 10 + start + i
                if low <= num <= high:
                    res.append(num)
        return sorted(res)
